use std::collections::HashSet;

fn solve(nums: Vec<i64>) -> i64 {
    if nums.is_empty() {
        return 0;
    }

    // 1. Get the set of unique initial values.
    let unique_nums_set: HashSet<i64> = nums.iter().cloned().collect();
    let unique_nums: Vec<i64> = unique_nums_set.into_iter().collect();

    // Map: original value -> minimum reachable value
    let mut min_reachable: std::collections::HashMap<i64, i64> = std::collections::HashMap::new();

    // 2. For every unique number u, find the minimum divisor 'd' of u such that 'd' is present in uniqueNums,
    // considering transitivity.
    for &u in &unique_nums {
        let mut reduced_value = u;
        let mut changed = true;

        // Iteratively reduce the value until it stabilizes (transitive closure)
        // This simulates repeatedly applying the rule: x -> d if x % d == 0 and d is in the set.
        while changed {
            changed = false;
            let mut next_reduced_value = reduced_value;

            // Check all potential targets 'd' in the initial set.
            for &d in &unique_nums {
                // We are looking for a divisor d that is smaller than the current reduced_value
                // and divides it.
                if d < reduced_value && reduced_value % d == 0 {
                    if d < next_reduced_value {
                        next_reduced_value = d;
                        changed = true;
                    }
                }
            }
            reduced_value = next_reduced_value;
        }

        min_reachable.insert(u, reduced_value);
    }

    // 3. Calculate the final sum.
    let mut total_sum: i64 = 0;
    for num in nums {
        // Look up the minimum reachable value for the current number.
        // Since num is guaranteed to be in unique_nums, it must be in min_reachable.
        let reduced = *min_reachable.get(&num).unwrap();
        total_sum += reduced;
    }

    total_sum
}
